// @vitest-environment node
/**
 * Source-tree hygiene tests: guard against committed leftover backup files.
 *
 * Regression guard for the code-quality finding that a stale `.bak` backup of
 * `src/app/toolbar-handlers.ts` (a verbatim copy of the OLD version, from
 * before the `clearSearch` function was added) was committed to the repository
 * by accident. Such files are dead weight: no build tool or import references
 * them, `tsc` only compiles `.ts` files under `src/` (so `.ts.bak` slips through unseen),
 * `.bak` is not covered by `.gitignore`, and a stale copy only confuses future
 * readers about which file is authoritative.
 *
 * This test walks the source tree and fails if ANY `.bak` file is present —
 * whether tracked by git or merely sitting in the working copy — so such
 * leftovers are caught before they ship.
 *
 * Pinned to the `node` environment (like `readme.test.ts`, `index.html.test.ts`
 * and `app.css.test.ts`) because it only inspects files on disk and needs no
 * DOM; this keeps it fast and side-effect-free.
 */
import { describe, it, expect } from 'vitest';
import { existsSync, readdirSync } from 'node:fs';
import { resolve, dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
// `src/` is the source tree whose cleanliness this test guards.
const SRC_DIR = resolve(__dirname);
// The exact leftover from the finding.
const TOOLBAR_BAK_PATH = resolve(__dirname, 'app/toolbar-handlers.ts.bak');

/**
 * Recursively collect the `SRC_DIR`-relative paths of every regular file under
 * `dir` whose name ends in `.bak` (case-insensitive, to also catch `.BAK`).
 *
 * Directories named `node_modules` or `.git` are skipped defensively — even
 * though the walk is rooted at `src/` today — so the helper stays correct if it
 * is ever pointed at a wider tree.
 *
 * Returns repo/source-relative paths (e.g. `app/toolbar-handlers.ts.bak`) so a
 * failure message names exactly which file(s) to delete.
 */
function findBackupFiles(dir: string, base: string = dir): string[] {
  const found: string[] = [];
  for (const entry of readdirSync(dir, { withFileTypes: true })) {
    if (entry.name === 'node_modules' || entry.name === '.git') {
      continue;
    }
    const full = join(dir, entry.name);
    if (entry.isDirectory()) {
      found.push(...findBackupFiles(full, base));
    } else if (entry.isFile() && entry.name.toLowerCase().endsWith('.bak')) {
      found.push(full.slice(base.length + 1));
    }
  }
  return found;
}

describe('source tree has no leftover .bak backup files', () => {
  it('contains zero `.bak` files anywhere under src/', () => {
    // The canonical guard: no backup file may pollute the source tree. A
    // non-empty list names the offending files so they can be removed.
    const backups = findBackupFiles(SRC_DIR);
    expect(
      backups,
      `expected no .bak files under src/, but found: ${backups.join(', ')}`,
    ).toEqual([]);
  });

  it('does not contain the stale src/app/toolbar-handlers.ts.bak', () => {
    // The specific leftover called out in the review: a pre-`clearSearch` copy
    // of toolbar-handlers.ts. It must be deleted entirely, not merely ignored
    // by the build.
    expect(existsSync(TOOLBAR_BAK_PATH)).toBe(false);
  });
});

